// determines the time weighted average, max and min of all payload values passed in
// over the specified time range passed to node by msg.filterTime in seconds
// developed from Code posted by Colin to Node_red Forum 
//     https://discourse.nodered.org/t/nodes-suggestion-for-timed-rolling-average-and-desynchronised-sum/4933/26 by Colin

if (typeof msg.filterTime == 'number') {
    flow.set('filterTime', msg.filterTime);
    node.warn(`Filter Time set to: ${msg.filterTime} seconds`);
    msg = null;
} else if (typeof msg.payload == 'number') {
    let filterTime = flow.get('filterTime') || 60 // in seconds
    const range = filterTime * 1000; // window time millisecs
    let buffer = flow.get('buffer') || [];
    let now = new Date();
    let lastTimestamp = flow.get("lastTimestamp") || now;
    let value = Number(msg.payload);
    // remove any samples that are too old
    // @ts-ignore
    while (buffer[0] && buffer[0].timestamp < now - range) {
        // remove oldest sample from array and total
        //node.warn(`removing oldest ${buffer[0].timestamp}`);
        lastTimestamp = buffer[0].timestamp;
        buffer.shift();
    }
    flow.set('lastTimestamp', lastTimestamp);

    // add the new sample to the end
    buffer.push({
        timestamp: now,
        value: value
    });
    // @ts-ignore
    let duration = (now - lastTimestamp); // difference between latest sample and oldest
    // now calculate Average, max and min
    let max = value;
    let min = value;
    let ave = 0;
    for (var i in buffer) {
        max = Math.max(max, buffer[i].value);
        min = Math.min(min, buffer[i].value);
        ave += buffer[i].value * (buffer[i].timestamp - lastTimestamp);
        lastTimestamp = buffer[i].timestamp;
    }
    ave = ave / duration;

    flow.set('buffer', buffer);
    //flow.set('total', total);
    msg.payload = max;
    msg.result = {
        average: ave,
        max: max,
        min: min
    };
    node.status({ text: `${buffer.length}` });
    //node.warn(`length: ${buffer.length}, average: ${ave}, min: ${min}, max: ${max} over ${duration/1000} seconds`);

};
return msg;

